"use client";
import { useEnvironmentContext } from "../../providers/environment/use-environment-context.js";
import { useLocaleContext } from "../../providers/locale/use-locale-context.js";
import * as dateInput from "@zag-js/date-input";
import { useId } from "react";
import { normalizeProps, useMachine } from "@zag-js/react";
//#region src/components/date-input/use-date-input.ts
var useDateInput = (props = {}) => {
	const id = useId();
	const { dir, locale } = useLocaleContext();
	const { getRootNode } = useEnvironmentContext();
	const context = {
		id,
		dir,
		locale,
		getRootNode,
		...props
	};
	const service = useMachine(dateInput.machine, context);
	return dateInput.connect(service, normalizeProps);
};
//#endregion
export { useDateInput };
